        // WebSocket
        function connectWS() {
            try {
                var ws = new WebSocket(WS_URL);
                ws.onopen = function() {
                    addLog('info', 'WebSocket 已连接');
                };
                ws.onclose = function() {
                    setTimeout(connectWS, 3000);
                };
                ws.onmessage = function(e) {
                    try {
                        var data = JSON.parse(e.data);
                        if (data.type === 'health') updateHealth(data);
                    } catch(err) {}
                };
            } catch(e) {
                addLog('warn', 'WebSocket 连接失败');
            }
        }
        function updateHealth(data) {
            var s = data.system || {};
            if (s.cpu !== undefined) {
                var bar = document.getElementById('cpuBar');
                bar.style.width = s.cpu + '%';
                bar.className = 'progress-fill ' + (s.cpu < 60 ? 'green' : s.cpu < 85 ? 'yellow' : 'red');
                document.getElementById('cpuVal').textContent = s.cpu + '%';
            }
            if (s.memory !== undefined) {
                var bar = document.getElementById('memBar');
                bar.style.width = s.memory + '%';
                bar.className = 'progress-fill ' + (s.memory < 60 ? 'green' : s.memory < 85 ? 'yellow' : 'red');
                document.getElementById('memVal').textContent = s.memory + '%';
            }
            if (s.disk !== undefined) {
                var bar = document.getElementById('diskBar');
                bar.style.width = s.disk + '%';
                bar.className = 'progress-fill ' + (s.disk < 70 ? 'green' : s.disk < 90 ? 'yellow' : 'red');
                document.getElementById('diskVal').textContent = s.disk + '%';
            }
        }

