        if (typeof updateRecordToggleUI === 'function') updateRecordToggleUI(false);
        if (typeof updateMediaOutputStatus === 'function') updateMediaOutputStatus('idle');
        var timeStr = new Date().toLocaleTimeString('en-US', { hour12: false });
        if (typeof mediaLog === 'function') mediaLog(timeStr + ' 停止录像', 'info');
    }).catch(function(e) { showToast('error', '录像停止异常: ' + e.message); });
}

