// WASM SDK 就绪后，监听容器尺寸变化
window.addEventListener('wasm:ready', function() {
    console.log('[MAIN] WASM SDK ready, attaching ResizeObserver');
    wasmObserveResize('divPlugin');
    if (typeof updateMediaInputStatus === 'function') updateMediaInputStatus('connecting');

    // 自动登录：如果设备已连接（ISAPI 已完成登录），WASM 自动登录
    if (window.connectedDevice && window.connectedDevice.ip) {
        console.log('[WASM] Device already connected, auto-login...');
        var ip = window.connectedDevice.ip;
        var port = window.connectedDevice.port || 80;
        var username = window.connectedDevice.username || 'admin';
        var password = window.connectedDevice.password || '';

        wasmLogin(ip, port, username, password).then(function(result) {
            console.log('[WASM] Auto-login result:', result);
        }).catch(function(err) {
            console.error('[WASM] Auto-login failed:', err);
        });
    }
});

// WASM 登录事件 → 更新媒体输入状态 + 操作日志
window.addEventListener('wasm:login', function(e) {
    if (typeof updateMediaInputStatus === 'function') updateMediaInputStatus('connecting');
    if (typeof operationLog === 'function') {
        var dev = window.connectedDevice;
        var name = dev ? (dev.name || dev.device_name || dev.ip) : (e.detail ? e.detail.ip : '设备');
        operationLog(name + ': ISAPI已连接', 'success');
    }
});

// WASM 播放开始 → 更新媒体输入为已连接
window.addEventListener('wasm:playing', function(e) {
    if (typeof updateStreamButtons === 'function') updateStreamButtons();
    if (typeof updateMediaInputStatus === 'function') updateMediaInputStatus('playing');
    var timeStr = new Date().toLocaleTimeString('en-US', { hour12: false });
    if (typeof mediaLog === 'function') mediaLog(timeStr + ' 开始播放', 'success');
});

// WASM 登出 → 更新状态
window.addEventListener('wasm:logout', function() {
    if (typeof updateMediaInputStatus === 'function') updateMediaInputStatus('idle');
});

