edits.newText:
function consoleSnapshot() {
    if (!WasmPlayer || !WasmPlayer.playing) {
        showToast('warning', '请先开始预览');
        return;
    }
    var dev = window.connectedDevice;
    var deviceName = (dev && (dev.name || dev.device_name || dev.ip) || 'device').replace(/[^a-zA-Z0-9\u4e00-\u9fa5_-]/g, '_');
    var filename = deviceName + '_' + new Date().toISOString().replace(/[-:T.]/g, '').substring(0, 14);
    var btn = document.getElementById('btnConsoleSnapshot');
    btn.disabled = true;
    btn.textContent = '抓取中...';
    wasmCapturePic(filename).then(function(result) {
        btn.disabled = false;
        btn.textContent = '📷 截图';
        if (result && result.success) {
            showToast('success', '截图成功');
            if (typeof operationLog === 'function') operationLog('截图', 'success');
            var timeStr = new Date().toLocaleTimeString('en-US', { hour12: false });
            if (typeof mediaLog === 'function') mediaLog(timeStr + ' 截图成功', 'success');
        } else {
            showToast('error', '截图失败');
        }
    }).catch(function(e) {
        btn.disabled = false;
        btn.textContent = '📷 截图';
        showToast('error', '截图异常: ' + e.message);
    });
}

edits.oldText:
function consoleSnapshot() {
    var dev = window.connectedDevice.ip;
    if (!dev) { showToast('warning', '请先选择设备'); return; }
    var btn = document.getElementById('btnConsoleSnapshot');
    btn.disabled = true;
    btn.textContent = '抓取中...';
    apiPost('/api/v1/ptz/' + dev + '/capture', null).then(function(result) {
        btn.disabled = false;
        btn.textContent = '📸 截图';
        if (result && result.success) {
            showToast('success', '截图成功: ' + (result.data ? result.data.filename : ''));
            if (typeof operationLog === 'function') operationLog('截图', 'success');
            if (result.data && result.data.image_path) {
                var preview = document.getElementById('consoleSnapshotPreview');
                var img = document.getElementById('consoleSnapshotImg');
                if (preview && img) {
                    img.alt = '截图: ' + result.data.filename;
                    preview.style.display = 'block';
                }
            }
        } else {
            showToast('error', result ? result.message : '截图失败');
        }
    }).catch(function(e) {
        btn.disabled = false;
        btn.textContent = '📸 截图';
        showToast('error', '截图异常: ' + e.message);
    });
}

