"""识图工具 - 调用 Qwen3.7 Plus Vision API"""
import base64, json, sys, urllib.request, os

API_URL = "https://coding.dashscope.aliyuncs.com/apps/anthropic/v1/messages"
API_KEY = "sk-sp-438656a7e1b740cdbac3f4d0f5369df7"
MAX_TOKENS = 1024

def analyze(image_path: str, prompt: str, max_tokens: int = MAX_TOKENS) -> str:
    """分析单张图片"""
    with open(image_path, 'rb') as f:
        img_b64 = base64.b64encode(f.read()).decode('utf-8')

    ext = os.path.splitext(image_path)[1].lower()
    mime_map = {'.png': 'image/png', '.jpg': 'image/jpeg', '.jpeg': 'image/jpeg', '.webp': 'image/webp', '.gif': 'image/gif'}
    media_type = mime_map.get(ext, 'image/png')

    data = {
        'model': 'qwen3.7-plus',
        'max_tokens': max_tokens,
        'messages': [{
            'role': 'user',
            'content': [
                {'type': 'image', 'source': {'type': 'base64', 'media_type': media_type, 'data': img_b64}},
                {'type': 'text', 'text': prompt}
            ]
        }]
    }

    req = urllib.request.Request(
        API_URL,
        data=json.dumps(data).encode('utf-8'),
        headers={
            'Content-Type': 'application/json',
            'x-api-key': API_KEY,
            'anthropic-version': '2023-06-01'
        }
    )

    with urllib.request.urlopen(req, timeout=60) as resp:
        result = json.loads(resp.read().decode('utf-8'))
        text = ""
        for block in result['content']:
            if block['type'] == 'text':
                text += block['text']
        return text

if __name__ == "__main__":
    try:
        image_path = sys.argv[1]
        prompt = " ".join(sys.argv[2:]) if len(sys.argv) > 2 else "请描述这张图片"
        result = analyze(image_path, prompt)
        print(result)
    except urllib.error.HTTPError as e:
        print(f"HTTP Error {e.code}: {e.read().decode('utf-8')[:500]}", file=sys.stderr)
    except Exception as e:
        print(f"Error: {e}", file=sys.stderr)

