"""深度诊断: _expose 数组和 window 暴露"""
from playwright.sync_api import sync_playwright

with sync_playwright() as p:
    browser = p.chromium.launch(headless=False)
    page = browser.new_page(viewport={"width": 1920, "height": 1080})

    errors = []
    page.on('pageerror', lambda err: errors.append(f'PAGE_ERROR: {err.message}'))
    page.on('console', lambda msg: errors.append(f'CONSOLE[{msg.type}]: {msg.text}') if msg.type in ('error',) else None)

    page.goto('http://127.0.0.1:10280', wait_until='domcontentloaded', timeout=30000)
    page.wait_for_timeout(8000)

    print("=== All errors ===")
    for e in errors:
        print(f'  {e[:200]}')

    print("\n=== _expose and window ===")
    info = page.evaluate("""() => {
        var result = {};
        // Check specific functions
        ['connectDevice','disconnectDevice','deleteDevice','toggleRecord','quickConnect','discoverDevices'].forEach(function(name) {
            result[name] = {
                onWindow: typeof window[name],
                equalsFn: typeof window[name] === 'function'
            };
        });

        // Try to access _expose (it's local to IIFE, might not be accessible)
        result._exposeAccessible = typeof _expose !== 'undefined';

        return result;
    }""")
    for k, v in info.items():
        print(f'  {k}: {v}')

    browser.close()
    print("Done")

