// 录像 (主控台版) - 使用 WASM SDK 官方方法
function consoleRecordStart() {
    if (!WasmPlayer || !WasmPlayer.playing) {
        showToast('warning', '请先开始预览');
        return;
    }
    var dev = window.connectedDevice;
    var deviceName = (dev && (dev.name || dev.device_name || dev.ip) || 'device').replace(/[^a-zA-Z0-9\u4e00-\u9fa5_-]/g, '_');
    var filename = deviceName + '_' + new Date().toISOString().replace(/[-:T.]/g, '').substring(0, 14);

    wasmStartRecord(filename).then(function(result) {
        if (result && result.success) {
            showToast('success', '录像已启动');
            if (typeof operationLog === 'function') operationLog('录像开始', 'warning');
            if (typeof updateRecordToggleUI === 'function') updateRecordToggleUI(true);
            updateMediaOutputStatus('recording');
            var timeStr = new Date().toLocaleTimeString('en-US', { hour12: false });
            mediaLog(timeStr + ' 开始录像...', 'warning');
        } else {
            showToast('error', '录像启动失败');
        }
    }).catch(function(e) { showToast('error', '录像异常: ' + e.message); });
}
function consoleRecordStop() {
    wasmStopRecord().then(function(result) {
        showToast('info', '录像已停止');
