        var ip = window.connectedDevice.ip;
        var port = window.connectedDevice.port || 80;
        var username = window.connectedDevice.username || 'admin';
        var password = window.connectedDevice.password || '';

        wasmLogin(ip, port, username, password).then(function(result) {
            console.log('[WASM] Auto-login result:', result);
        }).catch(function(err) {
            console.error('[WASM] Auto-login failed:', err);
        });
    }
});

