    if (typeof updateMediaInputStatus === 'function') updateMediaInputStatus('connecting');
    if (typeof operationLog === 'function') {
        var dev = window.connectedDevice;
        var name = dev ? (dev.name || dev.device_name || dev.ip) : (e.detail ? e.detail.ip : '设备');
        operationLog(name + ': ISAPI已连接', 'success');
    }
});

// WASM 播放开始 → 更新媒体输入为已连接
window.addEventListener('wasm:playing', function(e) {
    if (typeof updateStreamButtons === 'function') updateStreamButtons();
    if (typeof updateMediaInputStatus === 'function') updateMediaInputStatus('playing');
    var timeStr = new Date().toLocaleTimeString('en-US', { hour12: false });
    if (typeof mediaLog === 'function') mediaLog(timeStr + ' 开始播放', 'success');
});

// WASM 登出 → 更新状态
window.addEventListener('wasm:logout', function() {
    if (typeof updateMediaInputStatus === 'function') updateMediaInputStatus('idle');
});

