    var btn = document.getElementById('btnConsoleSnapshot');
    btn.disabled = true;
    btn.textContent = '抓取中...';
    wasmCapturePic(filename).then(function(result) {
        btn.disabled = false;
        btn.textContent = '📷 截图';
        if (result && result.success) {
            showToast('success', '截图成功');
            if (typeof operationLog === 'function') operationLog('截图', 'success');
            var timeStr = new Date().toLocaleTimeString('en-US', { hour12: false });
            if (typeof mediaLog === 'function') mediaLog(timeStr + ' 截图成功', 'success');
        } else {
            showToast('error', '截图失败');
        }
    }).catch(function(e) {
        btn.disabled = false;
        btn.textContent = '📷 截图';
        showToast('error', '截图异常: ' + e.message);
    });
}

