from playwright.sync_api import sync_playwright

with sync_playwright() as p:
    browser = p.chromium.launch(headless=False)
    page = browser.new_page(viewport={"width": 1920, "height": 1080})

    errors = []
    page.on('pageerror', lambda err: errors.append(err.message))

    page.goto('http://127.0.0.1:10280', wait_until='networkidle', timeout=30000)
    page.wait_for_timeout(5000)

    print('=== Page Errors ===')
    for e in errors:
        print(f'  {e}')

    # Test 1: Click nav buttons
    print('\n=== Nav Button Test ===')
    for name, sel in [("设备管理", '[data-page="devices"]'), ("主控台", '[data-page="console"]')]:
        btn = page.query_selector(sel)
        if btn:
            v = btn.is_visible()
            e = btn.is_enabled()
            rect = btn.bounding_box()
            print(f'  {name}: visible={v}, enabled={e}, rect={rect}')
            try:
                btn.click(timeout=3000)
                page.wait_for_timeout(1000)
                pid = f'page-{sel.split(chr(34))[1]}'
                pg = page.query_selector(f'#{pid}')
                if pg:
                    print(f'    -> {pid} active={pg.get_attribute("class")}')
                else:
                    print(f'    -> {pid} NOT FOUND')
            except Exception as ex:
                print(f'    -> click FAILED: {ex}')
        else:
            print(f'  {name}: NOT FOUND')

    # Test 2: quick connect switch
    print('\n=== Quick Connect Switch ===')
    qs = page.query_selector('#quickConnectSwitch')
    if qs:
        print(f'  可见: {qs.is_visible()}')
        bb = qs.bounding_box()
        print(f'  boundingBox: {bb}')
        parent = qs.evaluate("""el => {
            let p = el.closest('.status-item');
            if (!p) return null;
            let cs = getComputedStyle(p);
            return {display: cs.display, overflow: cs.overflow, width: cs.width, pointerEvents: cs.pointerEvents};
        }""")
        print(f'  parent status-item style: {parent}')
    else:
        print('  NOT FOUND')

    # Test 3: overall click blockers
    print('\n=== Z-Index / Click Blockers ===')
    blockers = page.evaluate("""() => {
        const r = [];
        document.querySelectorAll('*').forEach(el => {
            const cs = getComputedStyle(el);
            const z = parseInt(cs.zIndex) || 0;
            const rect = el.getBoundingClientRect();
            if (z > 10 && rect.width > 50 && rect.height > 50) {
                r.push({tag: el.tagName, id: el.id, cls: el.className.slice(0,60), z: z, 
                    x: rect.x.toFixed(0), y: rect.y.toFixed(0), w: rect.width.toFixed(0), h: rect.height.toFixed(0)});
            }
        });
        return r;
    }""")
    for b in blockers:
        print(f'  {b["tag"]}#{b["id"]} .{b["cls"]} z={b["z"]} @({b["x"]},{b["y"]}) {b["w"]}x{b["h"]}')

    page.screenshot(path='screenshots_v7.103/debug_buttons.png')
    browser.close()
    print('\nDone')

