// 确认重启/启动 - v8.01: 智能检测后端状态
window.confirmRestart = function() {
    // 先检查后端状态
    fetch('/control/status').then(r => r.json()).then(function(status) {
        if (status.running) {
            // 后端运行中，执行重启
            if (!confirm('确定要重启 AstroHub 吗?\n重启期间服务将暂时不可用。')) return;
            showToast('info', '正在重启...');
            fetch('/control/restart').then(r => r.json()).then(function(r) {
                showToast('success', '重启中，等待后端就绪...');
                waitForBackend();
            });
        } else {
            // 后端未运行，执行启动
            showToast('info', '正在启动后端...');
            fetch('/control/start').then(r => r.json()).then(function(r) {
                if (r.success) {
                    showToast('success', '后端启动中...');
                    waitForBackend();
                } else {
                    showToast('error', r.message || '启动失败');
                }
            });
        }
    }).catch(function(e) {
        // 静态服务器不可用，无法操作
        showToast('error', '控制服务不可用');
    });
};

// v8.01: 等待后端就绪
window.waitForBackend = function() {
    var overlay = document.getElementById('offline-overlay');
    if (overlay) overlay.classList.add('active');
    var checkInterval = setInterval(function() {
        fetch('/api/v1/version', {cache: 'no-store'}).then(function(r) {
            return r.json();
        }).then(function(data) {
            clearInterval(checkInterval);
            if (overlay) overlay.classList.remove('active');
            showToast('success', '后端已就绪');
            location.reload();
        }).catch(function() {
            // 继续等待
        });
    }, 2000);
};

// v8.01: 手动启动后端
window.startBackend = function() {
    fetch('/control/start').then(r => r.json()).then(function(r) {
        if (r.success) {
            showToast('success', '后端启动中...');
            waitForBackend();
        } else {
            showToast('error', r.message || '启动失败');
        }
    });
};

