"""v8.02 WASM 状态检查"""
from playwright.sync_api import sync_playwright

with sync_playwright() as p:
    b = p.chromium.launch(headless=False)
    page = b.new_page(viewport={"width": 1920, "height": 1080})
    errors = []
    page.on('pageerror', lambda err: errors.append(f'PAGE: {err.message}') if 'WebSocket' not in err.message else None)
    page.on('console', lambda msg: errors.append(f'CONSOLE[{msg.type}]: {msg.text}') if msg.type == 'error' else None)

    page.goto('http://127.0.0.1:10280', wait_until='domcontentloaded', timeout=30000)
    page.wait_for_timeout(20000)

    # 过滤掉 WS 连接断开等无关错误
    ws_errors = [e for e in errors if 'WebSocket' in e]
    other_errors = [e for e in errors if 'WebSocket' not in e]

    print('=== WASM 错误 ===')
    for e in other_errors[:10]:
        print(f'  {e[:200]}')

    # WASM 状态（避免直接引用 WasmPlayer）
    wasm = page.evaluate("""() => {
        const box = document.getElementById('mediaLogBox');
        const text = box ? box.textContent.trim() : 'NO BOX';
        const plugin = document.getElementById('divPlugin');
        const canvas = plugin ? plugin.querySelector('canvas') : null;
        return {
            log: text.substring(0, 500),
            hasCanvas: canvas !== null,
            canvasSize: canvas ? canvas.width + 'x' + canvas.height : 'N/A',
            connectedDevice: window.connectedDevice ? window.connectedDevice.ip : null,
            wsStatus: document.getElementById('wsStatus') ? document.getElementById('wsStatus').textContent : 'N/A',
            version: document.getElementById('version-display') ? document.getElementById('version-display').textContent : 'N/A'
        };
    }""")
    for k, v in wasm.items():
        print(f'  {k}: {v}')

    page.screenshot(path='screenshots_v7.103/v8.02_wasm.png')
    b.close()
    print('Done')

